pragma solidity ^0.8.15;

import {Ownable} from '@openzeppelin/contracts/access/Ownable.sol';

contract ControllableByContract is Ownable {
    event ControllerContractUpdated(address previousControllerContract, address newControllerContract);

    error Unauthorized();

    address public controllerContract;

    modifier onlyOwnerOrControllerContract() {
        if (msg.sender != owner() && msg.sender != controllerContract) {
            revert Unauthorized();
        }
        _;
    }

    constructor(address owner_) Ownable() {
        _transferOwnership(owner_);
    }

    function clearControllerContract() external onlyOwnerOrControllerContract {
        emit ControllerContractUpdated(controllerContract, address(0));
        delete controllerContract;
    }

    function setControllerContract(address newControllerContract) external onlyOwner {
        emit ControllerContractUpdated(controllerContract, newControllerContract);
        controllerContract = newControllerContract;
    }
}

pragma solidity 0.4.24;

import "./ExchangeWrapper.sol";
import "../DEX/Bancor.sol";

contract BancorWrapper is ExchangeWrapper {

    function getTokens(
        address converter,
        IERC20Token[] _path,
        uint256 _minReturn
    )
        external
        payable
    {
        Bancor(converter).quickConvert.value(msg.value)(_path, msg.value, _minReturn);
        // Get the last token in the token path
        IERC20Token token = _path[_path.length - 1];
        uint256 balance = token.balanceOf(address(this));
        token.transfer(msg.sender, balance);
    }

    function getEther(
        address converter,
        IERC20Token[] _path,
        uint256 _minReturn
    )
        external
    {
        // Get the first token in the token path
        IERC20Token token = _path[0];
        uint256 balance = token.balanceOf(address(this));

        if (IERC20Token(token).allowance(this, converter) < balance) {
            IERC20Token(token).approve(converter, MAX_UINT);
        }

        Bancor(converter).quickConvert(_path, balance, _minReturn);
        msg.sender.transfer(address(this).balance);
    }

}

